import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.jws.soap.SOAPBinding;
import javax.xml.XMLConstants;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.transform.Source;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.stream.StreamResult;
import java.io.StringReader;
import java.io.StringWriter;
import javax.xml.ws.Endpoint;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;
import org.xml.sax.InputSource;

@WebService
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT)
public interface DocumentProcessorService {

    @WebMethod
    String processXmlDocument(Source xmlDocument);
}

@WebService(endpointInterface = "DocumentProcessorService")
public class DocumentProcessorServiceImpl implements DocumentProcessorService {

    @Override
    public String processXmlDocument(Source xmlDocument) {
        StringBuilder result = new StringBuilder();
        try {
            // Convert the incoming JAX-WS Source object into a String.
            // This step is required to use DocumentBuilder.parse(InputSource) directly with a StringReader.
            // NOTE: For extremely large XML payloads (multi-gigabytes), converting to String might
            // lead to OutOfMemoryError. However, the requirement for DocumentBuilder implies DOM parsing,
            // which itself loads the entire document into memory, making this conversion less of a new bottleneck
            // compared to the inherent memory usage of DOM.
            String xmlString = sourceToString(xmlDocument);

            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();

            // Configure DocumentBuilderFactory for security and proper XML parsing:
            dbf.setNamespaceAware(true); // Recommended for modern XML processing
            dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true); // General security measure

            // XXE Prevention: Disable DTDs and external entity resolution
            // These features prevent various XML External Entity (XXE) attacks.
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true); // Disable DOCTYPE declarations
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false); // Disable external general entities
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false); // Disable external parameter entities
            dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false); // Prevent loading external DTDs

            dbf.setXIncludeAware(false); // Disable XInclude processing

            // The default for setExpandEntityReferences is true, which is needed to handle nested *internal* entities.
            // Since external entities are disabled, this only affects internal ones.

            DocumentBuilder db = dbf.newDocumentBuilder();

            // Parse the XML string into a Document object using the configured DocumentBuilder
            Document doc = db.parse(new InputSource(new StringReader(xmlString)));

            // --- Begin processing the Document ---
            Element root = doc.getDocumentElement();
            result.append("Root Element: ").append(root.getTagName()).append("\n");

            // Example: Traverse and count elements to demonstrate handling complex structures
            long elementCount = countElements(doc);
            result.append("Total Elements (including root): ").append(elementCount).append("\n");

            // Example: Extract data from specific tags and attributes, demonstrating nested entity handling
            NodeList informationBlocks = doc.getElementsByTagName("Information"); // Assuming some common tag
            if (informationBlocks.getLength() > 0) {
                for (int i = 0; i < informationBlocks.getLength(); i++) {
                    Element infoElement = (Element) informationBlocks.item(i);
                    result.append("  Information Block (Attributes: ");
                    for (int j = 0; j < infoElement.getAttributes().getLength(); j++) {
                        Node attr = infoElement.getAttributes().item(j);
                        result.append(attr.getNodeName()).append("=").append(attr.getNodeValue()).append(" ");
                    }
                    result.append("):\n");
                    // Access nested elements within the 'Information' block
                    NodeList subElements = infoElement.getChildNodes();
                    for (int j = 0; j < subElements.getLength(); j++) {
                        Node node = subElements.item(j);
                        if (node.getNodeType() == Node.ELEMENT_NODE) {
                            Element subElement = (Element) node;
                            result.append("    ").append(subElement.getTagName()).append(": ").append(subElement.getTextContent()).append("\n");

                            // Further nested element example
                            if ("Details".equals(subElement.getTagName())) {
                                NodeList detailItems = subElement.getElementsByTagName("SubDetail");
                                for (int k = 0; k < detailItems.getLength(); k++) {
                                    Element detailItem = (Element) detailItems.item(k);
                                    result.append("      SubDetail (category=")
                                          .append(detailItem.getAttribute("category"))
                                          .append("): ").append(detailItem.getTextContent()).append("\n");
                                }
                            }
                        }
                    }
                }
            } else {
                 result.append("No 'Information' blocks found for detailed extraction example.\n");
            }

            // For "large XML payloads for data import":
            // In a real data import scenario, you would iterate through relevant nodes
            // (e.g., "Record", "Item", "Transaction") to extract data and store it in a database
            // or another system. This example simulates that by processing "Record" elements.
            NodeList records = doc.getElementsByTagName("Record"); // Assuming records to import
            result.append("Found ").append(records.getLength()).append(" 'Record' elements for import.\n");
            for (int i = 0; i < records.getLength(); i++) {
                Element record = (Element) records.item(i);
                // Example: Extracting an attribute and child elements' text content
                String recordId = record.getAttribute("id");
                NodeList nameElements = record.getElementsByTagName("Name");
                String name = (nameElements.getLength() > 0) ? nameElements.item(0).getTextContent() : "N/A";
                NodeList valueElements = record.getElementsByTagName("Value");
                String value = (valueElements.getLength() > 0) ? valueElements.item(0).getTextContent() : "N/A";

                result.append("  Processing Record ID: ").append(recordId)
                      .append(", Name: ").append(name)
                      .append(", Value: ").append(value).append("\n");

                // In a real application:
                // dataService.saveRecord(recordId, name, value, ...);
            }

            result.append("XML document processed successfully.");

        } catch (Exception e) {
            System.err.println("Error processing XML document: " + e.getClass().getName() + ": " + e.getMessage());
            e.printStackTrace();
            return "Error: " + e.getClass().getName() + ": " + e.getMessage();
        }
        return result.toString();
    }

    // Helper method to convert a javax.xml.transform.Source object to a String.
    // This is necessary because DocumentBuilder.parse typically works with InputStream, File, or InputSource (from Reader/Stream).
    // A generic Source needs to be converted if we want to apply specific DocumentBuilderFactory settings.
    private String sourceToString(Source source) throws Exception {
        StringWriter stringWriter = new StringWriter();
        TransformerFactory transformerFactory = TransformerFactory.newInstance();
        Transformer transformer = transformerFactory.newTransformer();
        transformer.transform(source, new StreamResult(stringWriter));
        return stringWriter.toString();
    }

    // Recursive helper method to count all element nodes in a Document.
    private long countElements(Node node) {
        long count = 0;
        if (node.getNodeType() == Node.ELEMENT_NODE) {
            count++;
        }
        NodeList children = node.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            count += countElements(children.item(i));
        }
        return count;
    }
}

public class DocumentProcessorPublisher {

    public static void main(String[] args) {
        String url = "http://localhost:8080/documentprocessor";
        System.out.println("Publishing DocumentProcessorService at " + url);
        // The Endpoint.publish method creates a simple HTTP server to host the service.
        // It's suitable for development and testing. For production, deploy in a Servlet container
        // or JAX-WS compliant application server.
        Endpoint.publish(url, new DocumentProcessorServiceImpl());
        System.out.println("Service published. WSDL available at " + url + "?wsdl");
        System.out.println("Press Ctrl+C to stop the service.");
    }
}